+// transactionalReloadManager keeps the last good configuration in memory and
+// records the result of each reload attempt independently of the config file.
+type transactionalReloadManager struct {
+	mu        sync.RWMutex
+	path      string
+	knownGood *config.Config
+	status    api_v1.ReloadStatus
+}
+
+func newTransactionalReloadManager(path string) *transactionalReloadManager {
+	m := &transactionalReloadManager{path: path, status: emptyReloadStatus()}
+	b, err := os.ReadFile(path)
+	if err != nil {
+		return m
+	}
+	var status api_v1.ReloadStatus
+	if json.Unmarshal(b, &status) != nil || !validReloadCategory(status.ErrorCategory) {
+		return m
+	}
+	if status.AppliedReloaders == nil {
+		status.AppliedReloaders = []string{}
+	}
+	if status.ReloaderTimingsMS == nil {
+		status.ReloaderTimingsMS = map[string]float64{}
+	}
+	m.status = status
+	return m
+}
+
+func emptyReloadStatus() api_v1.ReloadStatus {
+	return api_v1.ReloadStatus{ErrorCategory: "none", AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]float64{}}
+}
+
+func validReloadCategory(category string) bool {
+	return category == "none" || category == "load_error" || category == "apply_error" || category == "rollback_error"
+}
+
+func (m *transactionalReloadManager) Status() api_v1.ReloadStatus {
+	m.mu.RLock()
+	defer m.mu.RUnlock()
+	return m.status
+}
+
+func (m *transactionalReloadManager) SetKnownGood(conf *config.Config) {
+	m.mu.Lock()
+	defer m.mu.Unlock()
+	m.knownGood = conf
+}
+
+func (m *transactionalReloadManager) Reload(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), rls ...reloader) (err error) {
+	start := time.Now()
+	status := emptyReloadStatus()
+	status.LastReloadID = start.UTC().Format(time.RFC3339)
+
+	defer func() {
+		if err == nil {
+			configSuccess.Set(1)
+			configSuccessTime.SetToCurrentTime()
+			callback(true)
+		} else {
+			configSuccess.Set(0)
+			callback(false)
+		}
+		status.LastReloadSuccessful = err == nil
+		m.record(status)
+	}()
+
+	logger.Info("Loading configuration file", "filename", filename)
+	conf, err := config.LoadFile(filename, agentMode, logger)
+	if err != nil {
+		status.ErrorCategory = "load_error"
+		status.ErrorMessage = err.Error()
+		return fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
+	}
+	if enableExemplarStorage && conf.StorageConfig.ExemplarsConfig == nil {
+		conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
+	}
+
+	for _, rl := range rls {
+		rstart := time.Now()
+		applyErr := rl.reloader(conf)
+		status.ReloaderTimingsMS[rl.name] = float64(time.Since(rstart)) / float64(time.Millisecond)
+		if applyErr == nil {
+			status.AppliedReloaders = append(status.AppliedReloaders, rl.name)
+			continue
+		}
+
+		status.ErrorCategory = "apply_error"
+		status.ErrorMessage = applyErr.Error()
+		status.FailedReloader = rl.name
+		logger.Error("Failed to apply configuration", "reloader", rl.name, "err", applyErr)
+		if len(status.AppliedReloaders) > 0 {
+			status.RollbackAttempted = true
+			if rollbackErr := m.rollback(rls); rollbackErr != nil {
+				status.RollbackSuccessful = false
+				status.ErrorCategory = "rollback_error"
+				status.ErrorMessage = fmt.Sprintf("apply failed in %s: %v; rollback failed: %v", rl.name, applyErr, rollbackErr)
+			} else {
+				status.RollbackSuccessful = true
+			}
+		}
+		return fmt.Errorf("failed to apply configuration with reloader %q: %w", rl.name, applyErr)
+	}
+
+	updateGoGC(conf, logger)
+	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	m.SetKnownGood(conf)
+	logger.Info("Completed loading of configuration file", "filename", filename, "totalDuration", time.Since(start))
+	return nil
+}
+
+func (m *transactionalReloadManager) rollback(rls []reloader) error {
+	m.mu.RLock()
+	conf := m.knownGood
+	m.mu.RUnlock()
+	if conf == nil {
+		return fmt.Errorf("no known-good configuration is available")
+	}
+	var errs []error
+	for _, rl := range rls {
+		if err := rl.reloader(conf); err != nil {
+			errs = append(errs, fmt.Errorf("%s: %w", rl.name, err))
+		}
+	}
+	return joinErrors(errs)
+}
+
+func (m *transactionalReloadManager) record(status api_v1.ReloadStatus) {
+	m.mu.Lock()
+	m.status = status
+	b, err := json.Marshal(status)
+	path := m.path
+	m.mu.Unlock()
+	if err != nil {
+		return
+	}
+	if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
+		return
+	}
+	// A rename prevents a restart from observing a partially-written outcome.
+	tmp, err := os.CreateTemp(filepath.Dir(path), ".reload-status-*")
+	if err != nil {
+		return
+	}
+	if _, err = tmp.Write(b); err == nil {
+		err = tmp.Chmod(0o644)
+	}
+	if closeErr := tmp.Close(); err == nil {
+		err = closeErr
+	}
+	if err == nil {
+		err = os.Rename(tmp.Name(), path)
+	}
+	if err != nil {
+		_ = os.Remove(tmp.Name())
+	}
+}
